import React from 'react';
import { findDOMNode } from 'react-dom';
import { observer, inject } from 'mobx-react';
import { errBoundary } from '@/components/ErrorBoundary';
import { Cascader } from 'antd';
import CommonStore, { enum_region_level } from '@/store/Common/typing';
import {} from '@/utils/method';
import {} from '@/utils/constant';
import { IRegionInfoBase, ISelectorOptions } from './constant';
import styles from './index.less';

interface IProps {
    commonStore: CommonStore;
    selectedHandler: (value: string[]) => void; // 区域选择的处理
}

interface IState {
    level: enum_region_level; // 当前层级
    provinceData: Record<string, IRegionInfoBase[]>; // 省列表对象
    cityData: Record<string, IRegionInfoBase[]>; // 市列表对象
    districtData: Record<string, IRegionInfoBase[]>; // 区列表对象
    optionList: ISelectorOptions[]; // 选项列表
    popupVisible: boolean; // 浮层显隐
    selectedValue: string[]; // 选择的区域
}

const REF_NAME = 'regionSelector';

@inject('uiStore', 'commonStore')
@observer
class RegionSelector extends React.Component<IProps, IState> {
    constructor(props: IProps) {
        super(props);
        this.state = {
            popupVisible: false,
            level: enum_region_level.province,
            provinceData: {},
            cityData: {},
            districtData: {},
            optionList: [],
            selectedValue: []
        };
    }
    componentDidMount() {
        this.initData(1);
    }
    /**
     * 数据加载
     * @param {number} region_id // 区域id
     * @return {void}
     */
    initData = async (region_id: number) => {
        const _this = this;
        const { level, provinceData, cityData, districtData } = _this.state;
        const { commonStore } = _this.props;
        const result = await commonStore.getRegionList(level, region_id);
        const { ifSuccess, data } = result;
        if (ifSuccess && data.length > 0) {
            switch (level) {
                case enum_region_level.province:
                    data.forEach((item: IRegionInfoBase) => {
                        provinceData[item.f_region_id] = [item];
                    });
                    break;
                case enum_region_level.city:
                    data.forEach((item: IRegionInfoBase) => {
                        if (cityData[region_id]) {
                            cityData[region_id].push(item);
                        } else {
                            cityData[region_id] = [item];
                        }
                    });
                    break;
                case enum_region_level.district:
                    data.forEach((item: IRegionInfoBase) => {
                        if (districtData[region_id]) {
                            districtData[region_id].push(item);
                        } else {
                            districtData[region_id] = [item];
                        }
                    });
                    break;
            }
            _this.optionComputed();
        }
    };
    optionComputed = () => {
        const _this = this;
        const { provinceData, cityData, districtData } = _this.state;
        const optionList: ISelectorOptions[] = Object.values(provinceData).map(provinceItem => {
            const provinceInfo = provinceItem[0];
            const provinceChildren = cityData[provinceInfo.f_region_id];
            return {
                label: provinceInfo.f_region_name,
                value: provinceInfo.f_region_id,
                children: provinceChildren
                    ? [
                          {
                              label: '全部',
                              value: 0
                          },
                          ...provinceChildren.map(cityInfo => {
                              const cityChildren = districtData[cityInfo.f_region_id];
                              return {
                                  label: cityInfo.f_region_name,
                                  value: cityInfo.f_region_id,
                                  children: cityChildren
                                      ? [
                                            {
                                                label: '全部',
                                                value: 0
                                            },
                                            ...cityChildren.map(districtInfo => {
                                                return {
                                                    label: districtInfo.f_region_name,
                                                    value: districtInfo.f_region_id
                                                };
                                            })
                                        ]
                                      : []
                              };
                          })
                      ]
                    : []
            };
        });
        _this.setState({
            optionList
        });
    };
    onChange = values => {
        const _this = this;
        const { cityData, districtData } = _this.state;
        let loadMoreStatus = true; // 加载下层级的数据
        const lastVal = values.slice(-1)[0];
        const newState = {};
        switch (values.length) {
            case 1:
                newState['level'] = enum_region_level.city;
                break;
            case 2:
                newState['level'] = enum_region_level.district;
                break;
            case 3:
                loadMoreStatus = false;
                break;
        }
        if (lastVal === 0 || !loadMoreStatus) {
            newState['popupVisible'] = false;
            _this.props.selectedHandler(values.filter(item => item !== 0));
        }
        if (lastVal === 0 || values.length === 3 || values.length === 0) {
            newState['popupVisible'] = false;
            newState['selectedValue'] = values;
            _this.props.selectedHandler(values.filter(item => item !== 0));
        }
        _this.setState(newState, () => {
            const { level } = _this.state;
            // 选中 ‘全部’ 或 区县层级 时，不再获取下层数据
            if (lastVal !== 0 && loadMoreStatus) {
                switch (level) {
                    case enum_region_level.city:
                        !cityData[lastVal] && _this.initData(lastVal);
                        break;
                    case enum_region_level.district:
                        !districtData[lastVal] && _this.initData(lastVal);
                        break;
                }
            }
        });
    };
    togglePopup = () => {
        this.setState({
            popupVisible: !this.state.popupVisible
        });
    };
    displayRender = (labels, selectedOptions) => {
        let lastLabel = labels.slice(-1)[0];
        if (lastLabel === '全部') {
            lastLabel = labels.slice(-2)[0];
        }
        return lastLabel;
    };

    render() {
        const _this = this;
        const { optionList, popupVisible, selectedValue } = _this.state;
        return (
            <Cascader
                ref={REF_NAME}
                allowClear
                changeOnSelect
                value={selectedValue}
                popupVisible={popupVisible}
                onClick={_this.togglePopup}
                options={optionList}
                onChange={_this.onChange}
                placeholder="全部区域"
                displayRender={_this.displayRender}
                style={{ width: 120 }}
                // getPopupContainer={() => document.getElementById(parentIdName)}
                getPopupContainer={() => findDOMNode(_this.refs[REF_NAME])}
            />
        );
    }
}

export default errBoundary(RegionSelector);
