import React from 'react';
import { errBoundary } from '@/components/ErrorBoundary';
import { Modal, Button } from 'antd';
import AnalysisStore, { enum_chart_type } from '@/store/Analysis/typings';
import { enum_export_type } from '../constant';
import styles from './ExportModal.less';

interface IProps {
    ifShow: boolean; // 弹窗显示隐藏状态
    toggleModal: Function; // 弹窗显示隐藏的处理
    timeText: string; // 时间
    analysisStore: AnalysisStore;
    exportHandler: (type: enum_export_type) => void; // 导出处理函数
}

interface IState {
    loadings: any[]; // 按钮loading控制
}

class ExportModal extends React.Component<IProps, IState> {
    constructor(props: IProps) {
        super(props);
        this.state = {
            loadings: []
        };
    }
    handleCancel = e => {
        this.props.toggleModal();
    };
    clickExport = (index: enum_export_type) => async () => {
        const newLoadings = [...this.state.loadings];
        newLoadings[index] = true;
        this.setState({
            loadings: newLoadings
        });
        await this.props.exportHandler(index);
        newLoadings[index] = false;
        this.setState({ loadings: newLoadings });
        this.props.toggleModal();
    };

    render() {
        const _this = this;
        const { loadings } = _this.state;
        const { ifShow, timeText, analysisStore } = _this.props;
        const { selectedChartType } = analysisStore;
        return (
            <Modal
                wrapClassName="comp-export-modal"
                title="下载单量报表Excel"
                visible={ifShow}
                onCancel={_this.handleCancel}
                cancelText="取消"
                okText="确定"
            >
                <div className={styles.container}>
                    <div className={styles.content}>
                        <div className={styles.title}>
                            时间：
                            <span className={styles.text}>{timeText}</span>
                        </div>
                        {/* <div className={styles.title}>
                            站点数：
                            <span className={styles.text}>{factoryNum}</span>
                        </div> */}
                    </div>
                    <div className={styles.footer}>
                        {selectedChartType !== enum_chart_type.repurchaseRate && (
                            <Button
                                className={styles.footerBtn}
                                loading={loadings[enum_export_type.factory]}
                                onClick={_this.clickExport(enum_export_type.factory)}
                                disabled={loadings[enum_export_type.region]}
                            >
                                按站点导出
                            </Button>
                        )}
                        <Button
                            className={`${styles.footerBtn} ${styles.regionBtn}`}
                            loading={loadings[enum_export_type.region]}
                            onClick={_this.clickExport(enum_export_type.region)}
                            disabled={loadings[enum_export_type.factory]}
                        >
                            按大区导出
                        </Button>
                    </div>
                </div>
            </Modal>
        );
    }
}

export default errBoundary(ExportModal);
