import React from 'react';
import { observer, inject } from 'mobx-react';
import FactoryModal from '@/components/FactoryModal';
import DateSelector from './components/DateSelector';
import ChartHeader from './components/ChartHeader';
import OrderCountChart from './components/OrderCountChart';
import RevenueChart from './components/RevenueChart';
import PositiveRateChart from './components/PositiveRateChart';
import ShareRateChart from './components/ShareRateChart';
import RepurchaseRateChart from './components/RepurchaseRateChart';
import BackBtn from '@/components/BackBtn';
import { errBoundary } from '@/components/ErrorBoundary';
import { UIStore } from '@/store/UI';
import AnalysisStore, {
    enum_date_type,
    enum_chart_type,
    enum_xAxis_type,
    IParticipateRateDODItem,
    ISelectedProvince,
    IRepurchaseRateDODItem,
    ITurnoverRateDODItem,
    enum_analysis_factory_type
} from '@/store/Analysis/typings';
import TargetSettingStore, { enum_month_name, enum_target_type } from '@/store/TargetSetting/typing';
import { CHART_TYPE_LIST, enum_area_type } from './constant';
import { formatDate, removeEmpty } from '@/utils/method';
import { Layout, Radio } from 'antd';
import styles from './index.less';

// 抽离重复使用了很多次的一组参数
interface IParams {
    startDate: string; // 开始时间
    endDate: string; // 结束时间
    endYear?: string; // 结束年份 目标值需要
    endMonth?: enum_month_name; // 结束月份 目标值需要
    others?: any; // 额外的一些参数
}

interface IProps {
    uiStore: UIStore;
    analysisStore: AnalysisStore;
    targetSettingStore: TargetSettingStore;
}

interface IState {
    ifFactoryModalShow: boolean; // 站点弹窗的显示状态
    ifDateModalShow: boolean; // 日期选择框的显示状态
    mainChartData: Record<string, any>[]; // 主要chart图表的渲染数据
    headerData: Record<string, any>[]; // 图表上方legend的数据
    participateData: IParticipateRateDODItem[]; // 参评率数据
    selectedProvinceData: ISelectedProvince; // 选中的省市
    selectedAreaType: enum_area_type; // 当前省市类型
    selectedFactoryIds: number[] | string[]; // 已选的站点id，逗号拼接
    selectedFactoryData: any[]; // 已选的站点数据
}

const { Header, Content } = Layout;

@inject('analysisStore', 'targetSettingStore', 'uiStore')
@observer
class Index extends React.Component<IProps, IState> {
    constructor(props: IProps) {
        super(props);
        this.state = {
            ifFactoryModalShow: false,
            ifDateModalShow: false,
            mainChartData: [],
            headerData: [],
            participateData: [],
            selectedProvinceData: {},
            selectedAreaType: enum_area_type.province,
            selectedFactoryIds: [],
            selectedFactoryData: []
        };
    }
    componentDidMount() {
        // 先计算时间，再判断 图表type（单量，营收，好评率，分享率，复购率），最后判断按时间分类 还是地区分类
        this.dateComputed();
    }
    /**
     * 根据dateType 日K 周K 月K 计算查询的日期范围
     * @param dateType 时间类型
     * @return {void}
     */
    dateComputed = (params: { others: any } = { others: null }): void => {
        const { selectedDateType, selectedDateRange, changeChartHeaderTips } = this.props.analysisStore;
        const { startDate, endDate } = selectedDateRange;
        if (startDate || endDate) {
            // 已经有开始时间和结束时间，则直接使用
            this.chartTypeHandler({ startDate, endDate });
            return;
        }
        const endTime = new Date(); // 结束时间 就是今天
        const endStr = formatDate(new Date(), 'YYYY-MM-DD');
        let startTime = endTime,
            startStr = ''; // 开始时间
        switch (selectedDateType) {
            case enum_date_type.day:
                startTime = new Date(endTime.getTime() - 30 * 24 * 60 * 60 * 1000); // 计算30天前的日期
                startStr = formatDate(startTime, 'YYYY-MM-DD');
                changeChartHeaderTips('近30天');
                break;
            case enum_date_type.week:
                const weekNo = endTime.getDay(); // 今天周几
                const mondayTime = endTime.getTime() - (weekNo === 0 ? 6 : weekNo - 1) * 24 * 60 * 60 * 1000; // 本周周一的日期    weekNo - 1 = 距离周一已经过了几天
                startTime = new Date(mondayTime - 25 * 7 * 24 * 60 * 60 * 1000); // 25 * 7 计算25周前的周一日期，
                startStr = formatDate(startTime, 'YYYY-MM-DD');
                changeChartHeaderTips('近26周');
                break;
            case enum_date_type.month:
                startStr = endTime.getFullYear() + '-01-01'; // 今年的1月1日
                changeChartHeaderTips(endTime.getFullYear() + '年');
                break;
        }
        const endYear = formatDate(endStr, 'YYYY');
        const endMonth = enum_month_name['M' + formatDate(endStr, 'MM')];
        this.chartTypeHandler({ startDate: startStr, endDate: endStr, endYear, endMonth, ...params });
    };
    /**
     * 根据当前图表类型进行不同处理
     * @param startDate 开始时间
     * @param endDate 结束时间
     * @return {void}
     */
    chartTypeHandler = async (params: IParams) => {
        const { uiStore, analysisStore } = this.props;
        uiStore.openLoading();
        switch (analysisStore.selectedChartType) {
            case enum_chart_type.orderCount:
                // 获取单量数据
                await this.getOrderCountData(params);
                break;
            case enum_chart_type.revenue:
                // 获取营收数据
                await this.getRevenueRateData(params);
                break;
            case enum_chart_type.positiveRate:
                // 获取好评率数据
                await this.getPositiveRateData(params);
                break;
            case enum_chart_type.shareRate:
                // 获取分享率数据
                await this.getShareRateData(params);
                break;
            case enum_chart_type.repurchaseRate:
                // 获取复购率数据
                await this.getRepurchaseRateData(params);
                break;
        }
        uiStore.closeLoading();
    };
    /**
     * 单量环比数据获取
     * @param startDate 开始时间
     * @param endDate 结束时间
     * @return {void}
     */
    getOrderCountData = async (params: IParams) => {
        const { startDate, endDate, others } = params;
        const { selectedProvinceData, selectedFactoryIds } = this.state;
        const { selectedDateType, selectedXAxisType, getOrderCountAnalysis } = this.props.analysisStore;
        const otherParams = {};
        if (selectedXAxisType !== enum_xAxis_type.time) {
            otherParams['type'] = 0;
            otherParams['group_province'] = 1;
        }
        selectedFactoryIds.length > 0 && (otherParams['f_factory_id'] = selectedFactoryIds.join(','));
        const result = await Promise.all([
            getOrderCountAnalysis(
                removeEmpty({
                    type: selectedDateType,
                    startTime: startDate,
                    endTime: endDate,
                    ...others,
                    ...otherParams,
                    ...selectedProvinceData
                })
            )
        ]);
        const { ifSuccess, data } = result[0];
        if (ifSuccess) {
            this.setState({
                mainChartData: data
            });
        }
    };
    /**
     * 营收环比数据获取
     * @param startDate 开始时间
     * @param endDate 结束时间
     * @return {void}
     */
    getRevenueRateData = async (params: IParams) => {
        const { startDate, endDate, endYear, endMonth, others } = params;
        const { selectedProvinceData, selectedFactoryIds } = this.state;
        const { f_province_id } = selectedProvinceData;
        const { selectedDateType, selectedXAxisType, getRevenueAnalysis } = this.props.analysisStore;
        const otherParams = {};
        if (selectedXAxisType !== enum_xAxis_type.time) {
            otherParams['type'] = 0;
            otherParams['group_province'] = 1;
        }
        selectedFactoryIds.length > 0 && (otherParams['f_factory_id'] = selectedFactoryIds.join(','));
        const result = await Promise.all([
            getRevenueAnalysis({
                type: selectedDateType,
                f_skill_score: enum_analysis_factory_type.self,
                startTime: startDate,
                endTime: endDate,
                ...others,
                ...otherParams,
                ...selectedProvinceData
            }),
            this.props.targetSettingStore.getTargetList({
                f_year: endYear,
                f_month: endMonth,
                f_province_id,
                f_type: enum_target_type.profit
            })
        ]);
        const { ifSuccess, data } = result[0];
        if (ifSuccess) {
            this.setState({
                mainChartData: data
            });
        }
    };
    /**
     * 好评率环比数据获取
     * @param startDate 开始时间
     * @param endDate 结束时间
     * @return {void}
     */
    getPositiveRateData = async (params: IParams) => {
        const { startDate, endDate, endYear, endMonth, others } = params;
        const { selectedProvinceData, selectedFactoryIds } = this.state;
        const { f_province_id } = selectedProvinceData;
        const {
            selectedDateType,
            selectedXAxisType,
            getPositiveRateAnalysis,
            getPositiveRateGroupByDiscount,
            getParticipateRateAnalysis
        } = this.props.analysisStore;
        const otherParams = {};
        if (selectedXAxisType !== enum_xAxis_type.time) {
            otherParams['type'] = 0;
            otherParams['group_province'] = 1;
        }
        selectedFactoryIds.length > 0 && (otherParams['f_factory_id'] = selectedFactoryIds.join(','));
        const result = await Promise.all([
            getPositiveRateAnalysis({
                type: selectedDateType,
                startTime: startDate,
                endTime: endDate,
                ...others,
                ...otherParams,
                ...selectedProvinceData
            }),
            getPositiveRateGroupByDiscount({ startTime: startDate, endTime: endDate }),
            getParticipateRateAnalysis({
                type: selectedDateType,
                startTime: startDate,
                endTime: endDate,
                ...others,
                ...otherParams,
                ...selectedProvinceData
            }),
            this.props.targetSettingStore.getTargetList({
                f_year: endYear,
                f_month: endMonth,
                f_province_id,
                f_type: enum_target_type.positiveRate
            })
        ]);
        const { ifSuccess: mainChartSuccess, data: mainChartData } = result[0];
        const { ifSuccess: headerSuccess, data: headerData } = result[1];
        const { ifSuccess: participateSuccess, data: participateData } = result[2];
        if (mainChartSuccess && headerSuccess && participateSuccess) {
            this.setState({
                mainChartData,
                headerData,
                participateData
            });
        }
    };
    /**
     * 分享率环比数据获取
     * @param startDate 开始时间
     * @param endDate 结束时间
     * @return {void}
     */
    getShareRateData = async (params: IParams) => {
        const { startDate, endDate, endYear, endMonth, others } = params;
        const { selectedProvinceData, selectedFactoryIds } = this.state;
        const { f_province_id } = selectedProvinceData;
        const { selectedDateType, selectedXAxisType, getShareRateAnalysis } = this.props.analysisStore;
        const otherParams = {};
        if (selectedXAxisType !== enum_xAxis_type.time) {
            otherParams['type'] = 0;
            otherParams['group_province'] = 1;
        }
        selectedFactoryIds.length > 0 && (otherParams['f_factory_id'] = selectedFactoryIds.join(','));
        const result = await Promise.all([
            getShareRateAnalysis({
                type: selectedDateType,
                startTime: startDate,
                endTime: endDate,
                ...others,
                ...otherParams,
                ...selectedProvinceData
            }),
            this.props.targetSettingStore.getTargetList({
                f_year: endYear,
                f_month: endMonth,
                f_province_id,
                f_type: enum_target_type.shareRate
            })
        ]);
        const { ifSuccess, data } = result[0];
        if (ifSuccess) {
            this.setState({
                mainChartData: data
            });
        }
    };
    /**
     * 复购率环比数据获取
     * @param startDate 开始时间
     * @param endDate 结束时间
     * @return {void}
     */
    getRepurchaseRateData = async (params: IParams) => {
        const { startDate, endDate, endYear, endMonth, others } = params;
        const { selectedProvinceData, selectedFactoryIds } = this.state;
        const { f_province_id } = selectedProvinceData;
        const {
            selectedDateType,
            selectedXAxisType,
            getRepurchaseRateAnalysis,
            getTurnoverRateAnalysis
        } = this.props.analysisStore;
        const otherParams = {};
        if (selectedXAxisType !== enum_xAxis_type.time) {
            otherParams['type'] = 0;
            otherParams['group_province'] = 1;
        }
        selectedFactoryIds.length > 0 && (otherParams['f_factory_id'] = selectedFactoryIds.join(','));
        const result = await Promise.all([
            getRepurchaseRateAnalysis({
                type: selectedDateType,
                startTime: startDate,
                endTime: endDate,
                ...others,
                ...otherParams,
                ...selectedProvinceData
            }),
            getTurnoverRateAnalysis({
                type: selectedDateType,
                startTime: startDate,
                endTime: endDate,
                ...others,
                ...otherParams,
                ...selectedProvinceData
            }),
            this.props.targetSettingStore.getTargetList({
                f_year: endYear,
                f_month: endMonth,
                f_province_id,
                f_type: enum_target_type.repurchaseRate
            })
        ]);
        const { ifSuccess: repurchaseSuccess, data: repurchaseData } = result[0];
        const { ifSuccess: turnoverSuccess, data: turnoverData } = result[1];
        if (repurchaseSuccess && turnoverSuccess) {
            const newData = Array.from(repurchaseData);
            newData.forEach((item, index) => {
                item = Object.assign(item, turnoverData[index]);
            });
            this.setState({
                mainChartData: newData
            });
        }
    };
    /**
     * 选择时间类型 日K 周K 月K
     * @param event 事件对象
     * @return {void}
     */
    changeDateKType = dateType => {
        const _this = this;
        const {
            selectedDateType,
            selectedDateRange,
            changeDateType,
            changeSelectedDateRange
        } = _this.props.analysisStore;
        if (dateType === selectedDateType && !selectedDateRange.endDate) return;
        // 清空选择的省市区
        _this.setState(
            {
                selectedProvinceData: {},
                selectedAreaType: enum_area_type.province
            },
            () => {
                changeDateType(dateType);
                changeSelectedDateRange({ startDate: '', endDate: '' }); // 清除时间区间的选择
                _this.dateComputed();
            }
        );
    };
    /**
     * 选择图表类型 单量 营收 好评率 复购 支出 全局
     * @param event 事件对象
     * @return {void}
     */
    changeChartType = event => {
        const _this = this;
        const { value } = event.target;
        const { changeChartType } = _this.props.analysisStore;
        _this.setState(
            {
                selectedProvinceData: {},
                selectedAreaType: enum_area_type.province
            },
            () => {
                changeChartType(value);
                _this.dateComputed();
            }
        );
    };
    /**
     * 选择横坐标类型 时间 地区
     * @param event 事件对象
     * @return {void}
     */
    changeXAxisType = event => {
        const _this = this;
        const { value } = event.target;
        this.props.analysisStore.changeXAxisTypeType(value);
        // 清空选择的省市区
        this.setState(
            {
                selectedProvinceData: {},
                selectedAreaType: enum_area_type.province
            },
            _this.dateComputed
        );
    };
    /**
     * 点击图表的事件，省市区切换
     * @param selectedData 选中的图表对应的数据
     * @return {void}
     */
    chartClickHandler = selectedData => {
        const { selectedProvinceData } = this.state;
        const { selectedXAxisType } = this.props.analysisStore;
        const { f_province_id, f_city_id, f_district_id } = selectedData;
        if (selectedXAxisType !== enum_xAxis_type.time) {
            let areaType = enum_area_type.province;
            const newSelected = { ...selectedProvinceData };
            // 不精确到镇
            // if (f_district_id && !selectedProvinceData.f_district_id) {
            //     newSelected.group_district = 1;
            //     newSelected.f_district_id = f_district_id;
            //     areaType = enum_area_type.district;
            // } else
            if (f_city_id && !selectedProvinceData.f_city_id) {
                newSelected.group_district = 1;
                newSelected.f_city_id = f_city_id;
                areaType = enum_area_type.district;
            } else if (f_province_id && !selectedProvinceData.f_province_id) {
                newSelected.group_city = 1;
                newSelected.f_province_id = f_province_id;
                areaType = enum_area_type.city;
            } else {
                return;
            }
            this.setState({ selectedProvinceData: newSelected, selectedAreaType: areaType }, this.dateComputed);
        }
    };
    factorySelectedHandler = (ids, values) => {
        this.setState(
            {
                selectedFactoryIds: ids,
                selectedFactoryData: values
            },
            this.dateComputed
        );
    };
    /**
     * 日期选择框的显示隐藏
     * @return {void}
     */
    toggleDateModal = () => {
        this.setState({
            ifDateModalShow: !this.state.ifDateModalShow
        });
    };
    toggleFactoryModal = () => {
        this.setState({
            ifFactoryModalShow: !this.state.ifFactoryModalShow
        });
    };

    render() {
        const _this = this;
        const {
            ifFactoryModalShow,
            ifDateModalShow,
            mainChartData,
            headerData,
            participateData,
            selectedAreaType,
            selectedFactoryData
        } = _this.state;
        const { analysisStore, targetSettingStore } = _this.props;
        const { selectedChartType, selectedDateType, selectedXAxisType } = analysisStore;
        const chartProps = {
            dateType: selectedDateType,
            xAxisType: selectedXAxisType,
            data: mainChartData,
            areaType: selectedAreaType,
            selectedFactoryData,
            clickHandler: _this.chartClickHandler,
            targetSettingStore
        };
        return (
            <div
                id="page-analysis"
                onClick={() => {
                    ifDateModalShow && _this.toggleDateModal();
                }}
            >
                <FactoryModal
                    ifShow={ifFactoryModalShow}
                    toggleModal={_this.toggleFactoryModal}
                    okHandler={_this.factorySelectedHandler}
                />
                <Header className={styles.header}>
                    <div className={styles.headerLeft}>
                        <BackBtn />
                        <div onClick={_this.toggleFactoryModal} className={styles.headerTitle}>
                            {selectedFactoryData.length > 1
                                ? `${selectedFactoryData[0].f_name} 等站点`
                                : selectedFactoryData.length > 0
                                ? selectedFactoryData[0].f_name
                                : '全部站点'}
                        </div>
                        {selectedChartType === enum_chart_type.orderCount && (
                            <div className={styles.headerTag}>A级</div>
                        )}
                    </div>
                    <div className={styles.headerMiddle}>
                        {CHART_TYPE_LIST.map((chartTypeItem, index) => (
                            <Radio.Group
                                key={index}
                                defaultValue={-1}
                                value={selectedChartType}
                                onChange={_this.changeChartType}
                                className={chartTypeItem.length > 1 ? 'middleBtnGroup' : 'middleBtnSingle'}
                                buttonStyle="solid"
                            >
                                {chartTypeItem.map(item => (
                                    <Radio.Button key={item.value} value={item.value}>
                                        {item.title}
                                    </Radio.Button>
                                ))}
                            </Radio.Group>
                        ))}
                    </div>
                    <div className={styles.headerRight}>
                        <DateSelector
                            ifShow={ifDateModalShow}
                            toggleDateModal={_this.toggleDateModal}
                            dateRangeChangeHandler={_this.dateComputed}
                            dateTypeChangeHandler={_this.changeDateKType}
                            analysisStore={analysisStore}
                        />
                    </div>
                </Header>
                <Content className={styles.container}>
                    <div className={styles.main}>
                        <ChartHeader
                            mainChartData={mainChartData}
                            headerData={headerData}
                            selectedFactoryData={selectedFactoryData}
                            analysisStore={analysisStore}
                            targetSettingStore={targetSettingStore}
                            xAxisTypeChangeHandler={_this.changeXAxisType}
                            changeData={_this.dateComputed}
                        />
                        {selectedChartType === enum_chart_type.orderCount && <OrderCountChart {...chartProps} />}
                        {selectedChartType === enum_chart_type.revenue && <RevenueChart {...chartProps} />}
                        {selectedChartType === enum_chart_type.positiveRate && (
                            <PositiveRateChart participateData={participateData} {...chartProps} />
                        )}
                        {selectedChartType === enum_chart_type.shareRate && <ShareRateChart {...chartProps} />}
                        {selectedChartType === enum_chart_type.repurchaseRate && (
                            <RepurchaseRateChart {...chartProps} />
                        )}
                    </div>
                </Content>
            </div>
        );
    }
}

export default errBoundary(Index);
