import React from 'react';
import { View, Geom, Guide } from 'bizcharts';
import { errBoundary } from '@/components/ErrorBoundary';
import CompoundChart, { IGeom, enum_geom_type } from '@/components/CompoundChart';
import { IOrderDODItem, enum_date_type, enum_xAxis_type } from '@/store/Analysis/typings';
import { enum_area_type, simpleRegionName } from '../constant';
import { getWeekDayName, formatDate, debounce, getTicks, getSize, getRange } from '@/utils/method';
import styles from './OrderCountChart.less';

interface IProps {
    dateType: enum_date_type; // 查询的日期类型
    xAxisType: enum_xAxis_type; // 查询的x轴类型
    data: Record<string, any>[]; // 图表数据
    areaType: enum_area_type; // 当前横坐标字段名
    selectedFactoryData: any[]; // 当前选中站点
    clickHandler: Function; // 图形的点击事件
}

interface IState {
    activeData: Record<string, any>; // 当前选中的数据
    activeInterval: string; // 当前选中的柱状 横坐标字段内容
    activeGroup: string; // 当前选中的柱状 分组名称 主要用来区分层叠柱状图年份 如 2019 2020
}

class OrderChart extends React.Component<IProps, IState> {
    constructor(props: IProps) {
        super(props);
        this.state = {
            activeData: {},
            activeInterval: '',
            activeGroup: ''
        };
    }

    render() {
        const _this = this;
        const { activeData, activeInterval, activeGroup } = this.state;
        const { data, dateType, xAxisType, areaType, selectedFactoryData, clickHandler } = this.props;
        const titleKey = 'num',
            titleName = '总单量',
            yKeyName = 'yValue';
        let xKeyName = '';
        if (xAxisType === enum_xAxis_type.time) {
            switch (dateType) {
                case enum_date_type.day:
                    xKeyName = 'day';
                    break;
                case enum_date_type.week:
                    xKeyName = 'week';
                    break;
                case enum_date_type.month:
                    xKeyName = 'month';
                    break;
            }
        } else {
            xKeyName = areaType;
        }
        // 计算辅助线文本的偏移量
        const getGuideOffset = length => {
            // 以20个tick需要偏移0.5个tick为基准，换算偏移量
            return length + (length / 20 - 1) * 0.5;
        };
        // 单量geom
        const ORDER_GEOM_LIST: IGeom[] = [
            {
                type: enum_geom_type.INTERVAL,
                adjust: 'stack',
                // ...(dateType === enum_date_type.month ? { adjust: 'dodge' } : { adjust: 'stack' }),
                size: getSize(40),
                configList: [
                    {
                        typeKey: 'f_old_user_num', // 通过typeKey在data中找到对应字段的值。替代yKeyName的值
                        typeName: '老用户',
                        color: '#FDD903'
                    },
                    {
                        typeKey: 'f_new_user_num', // 通过typeKey在data中找到对应字段的值。替代yKeyName的值
                        typeName: '新用户',
                        color: '#AECA7E'
                    }
                ],
                // configList:
                //     dateType === enum_date_type.month
                //         ? [
                //               {
                //                   typeKey: 'num', // 通过typeKey在data中找到对应字段的值。替代yKeyName的值
                //                   typeName: data => {
                //                       const newTypeName = data.month.split('-')[0];
                //                       return newTypeName;
                //                   }, // 以typeName分组
                //                   newXValue: data => {
                //                       const newTypeName = data.month.split('-')[1];
                //                       return newTypeName;
                //                   },
                //                   color: ['#FDD903', '#D6B455']
                //               }
                //           ]
                //         : [
                //               {
                //                   typeKey: 'f_old_user_num', // 通过typeKey在data中找到对应字段的值。替代yKeyName的值
                //                   typeName: '老用户',
                //                   color: '#FDD903'
                //               },
                //               {
                //                   typeKey: 'f_new_user_num', // 通过typeKey在data中找到对应字段的值。替代yKeyName的值
                //                   typeName: '新用户',
                //                   color: '#AECA7E'
                //               }
                //           ],
                otherOptions: {
                    active: [
                        true,
                        {
                            highLight: {
                                fill: '#FFC400'
                            }
                        }
                    ]
                }
            }
        ];

        // 坐标轴配置
        const xConfig = {
            name: xKeyName,
            line: {
                // x轴宽度 颜色
                lineWidth: 1,
                stroke: '#979797'
            },
            tickLine: null,
            label: {
                offset: 0,
                autoRotate: false, // 文本是否需要自动旋转，默认为 true
                /**
                 * 使用 html 渲染文本
                 * @param  {string} text  文本值
                 * @param  {object} item  该文本值对应的原始数据记录
                 * @param  {number} index 索引值
                 * @return {string}       返回 html 字符串
                 */
                htmlTemplate: (text, item, index) => {
                    const axisContent = {
                        line1: '',
                        line2: ''
                    };
                    if (xAxisType === enum_xAxis_type.time) {
                        switch (dateType) {
                            case enum_date_type.day:
                                axisContent.line1 =
                                    text === activeInterval ? formatDate(text, 'MM/DD') : getWeekDayName(text);
                                // axisContent.line2 = '晴';
                                break;
                            case enum_date_type.week:
                                const weekArr = text.split('-');
                                axisContent.line1 = `${+weekArr[1]}周`;
                                axisContent.line2 = `${+weekArr[0]}`;
                                break;
                            case enum_date_type.month:
                                const monthArr = text.split('-');
                                axisContent.line1 = text === activeInterval ? `${+monthArr[1]}月` : monthArr[1];
                                axisContent.line2 = monthArr[0];
                                break;
                            // case enum_date_type.month:
                            //     axisContent.line1 = text === activeInterval ? `${+text}月` : text;
                            //     axisContent.line2 = text === activeInterval ? activeGroup : '';
                            //     break;
                        }
                    } else {
                        axisContent.line1 = simpleRegionName(text);
                    }
                    return `<div class="${styles.dayAxis} ${text === activeInterval ? styles.activeDayAxis : ''}">
                        <div style="${axisContent.line1 === '一' && text !== activeInterval ? 'color: #FF6704' : ''}">
                            ${axisContent.line1}
                        </div>
                        ${selectedFactoryData.length === 1 ? `<div>${axisContent.line2}</div>` : ''}
                    </div>`;
                }
            }
        };
        const yConfig = {
            name: yKeyName,
            visible: false
        };

        const toolTipConfig = {
            shared: dateType === enum_date_type.month ? false : true, // true tooltip合并 false tooltip分离
            useHtml: true,
            crosshairs: null,
            htmlContent: (title, items) => {
                const { _origin: data }: { _origin: IOrderDODItem } = items[0].point;
                return `<div class=${styles.diyToolContainer}>
                    <div class=${styles.diyToolHeader}>
                        <div>${titleName}：</div>
                        <div class=${styles.orderValue}>${data[titleKey]}</div>
                    </div>
                    <div class=${styles.diyToolLegend}>
                        <div class=${styles.diyToolLegendRow}>
                            <div class=${styles.icon} style="background: #AECA7E"></div>
                            <div>新用户 ${data.f_new_user_num}</div>
                        </div>
                        <div class=${styles.diyToolLegendRow}>
                            <div class=${styles.icon} style="background: #FDD903"></div>
                            <div>老用户 ${data.f_old_user_num}</div>
                        </div>
                    </div>
                    <div class=${styles.diyToolContent}>
                        <div>单站均单：${(data.num / data.factoryNum).toFixed(2)}</div>
                        <div>站点数：${data.factoryNum}</div>
                        <div>成交率：${(+data.successRate || 0).toFixed(2)}%</div>
                    </div>
                </div>`;
            }
        };

        const chartChildren = () => {
            const yKey = 'successRate';
            const { maxY, minY } = getRange(data, yKey);
            const aveNum = Math.round(
                data.reduce((preTotal, item) => {
                    return preTotal + item.num;
                }, 0) / data.length
            );
            return (
                <React.Fragment>
                    <View
                        data={data.map(item => ({ ...item, [yKey]: +item[yKey] }))}
                        scale={{
                            [yKey]: {
                                min: minY,
                                max: maxY
                            }
                        }}
                    >
                        <Geom
                            type={enum_geom_type.LINE}
                            position={`${xConfig.name}*${yKey}`}
                            size={getSize(3)}
                            color="#6ABD08"
                            opacity={1}
                        />
                    </View>
                    <Guide>
                        <Guide.Line
                            // top // {boolean} 指定 guide 是否绘制在 canvas 最上层，默认为 false, 即绘制在最下层
                            start={[-1, aveNum]} // -1 代表ticks索引，必须scale的type为非线性
                            end={[getGuideOffset(data.length), aveNum]} // 同 start
                            lineStyle={{
                                stroke: '#615616', // 线的颜色
                                lineDash: [1, 0], // 虚线的设置，实线
                                opacity: 1,
                                lineWidth: 3 // 线的宽度
                            }} // {object} 图形样式配置 https://bizcharts.net/products/bizCharts/api/graphic#线条样式
                        />
                        <Guide.Html
                            position={[getGuideOffset(data.length), aveNum]} // html 的中心位置， 值为原始数据值，支持 callback
                            offsetX={0}
                            offsetY={0}
                            html={`<div class=${styles.guideContainer}>
                                <div class=${styles.guideTitle}>平均</div>
                                <div class=${styles.guideTag}>${aveNum}</div>
                            </div>`}
                        />
                    </Guide>
                </React.Fragment>
            );
        };

        return (
            <div id="page-analysis-mainChart" className={styles.mainContainer}>
                <div className={styles.chartCard}>
                    <CompoundChart
                        data={data}
                        xConfig={xConfig}
                        yConfig={yConfig}
                        padding={['auto', '5%', 'auto', '2%']}
                        ifCanClick={xAxisType !== enum_xAxis_type.time && Boolean(activeInterval)}
                        scale={{
                            [xConfig.name]: {
                                type: 'cat',
                                ...(dateType === enum_date_type.month
                                    ? {}
                                    : {
                                          ticks: getTicks({
                                              length: data.length,
                                              activeTick: data.findIndex(item => item[xKeyName] === activeInterval)
                                          })
                                      })
                            },
                            [yConfig.name]: {
                                min: 0
                            }
                        }}
                        toolTipConfig={toolTipConfig}
                        geomList={ORDER_GEOM_LIST}
                        chartChildren={chartChildren()}
                        eventObj={{
                            onTooltipChange: debounce(event => {
                                const { _origin: data } = event.items[0].point;
                                (activeInterval !== data[xKeyName] || activeGroup !== data['groupName']) &&
                                    _this.setState({
                                        activeData: data,
                                        activeInterval: data[xKeyName],
                                        activeGroup: data['groupName']
                                    });
                            }, 0),
                            onTooltipHide: debounce(event => {
                                (activeInterval !== '' || activeGroup !== '') &&
                                    _this.setState({
                                        activeData: {},
                                        activeInterval: '',
                                        activeGroup: ''
                                    });
                            }, 0),
                            onPlotClick: debounce(event => {
                                if (activeInterval) {
                                    clickHandler(activeData);
                                }
                            }, 100)
                        }}
                    />
                </div>
            </div>
        );
    }
}

export default errBoundary(OrderChart);
