import React from 'react';
import { history } from 'umi';
import { inject, observer } from 'mobx-react';
import { View, Geom, Guide } from 'bizcharts';
import { errBoundary } from '@/components/ErrorBoundary';
import CompoundChart, { IGeom, enum_geom_type } from '@/components/CompoundChart';
import {
    enum_date_type,
    enum_xAxis_type,
    enum_comment_type,
    IPositiveRateDODItem,
    initPositiveRateDODItem,
    IParticipateRateDODItem,
    initParticipateRateDODItem
} from '@/store/Analysis/typings';
import TargetSettingStore, { enum_target_type } from '@/store/TargetSetting/typing';
import { enum_area_type, simpleRegionName } from '../constant';
import { getWeekDayName, formatDate, debounce, getTicks, getSize, getRange } from '@/utils/method';
import styles from './PositiveRateChart.less';

interface IProps {
    dateType: enum_date_type; // 查询的日期类型
    xAxisType: enum_xAxis_type; // 查询的x轴类型
    data: Record<string, any>[]; // 图表数据
    participateData: IParticipateRateDODItem[]; // 参评率数据
    areaType: enum_area_type; // 当前横坐标字段名
    clickHandler: Function; // 图形的点击事件
    targetSettingStore: TargetSettingStore;
}

interface IState {
    activeData: Record<string, any>; // 当前选中的数据
    activeInterval: string; // 当前选中的柱状 横坐标字段内容
}

const TARGET_TAG_ID_NAME = 'positiveRate-target-tag'; // 目标值tag的dom id名称

class PositiveRateChart extends React.Component<IProps, IState> {
    private targetTagDom;
    constructor(props: IProps) {
        super(props);
        this.state = {
            activeData: {},
            activeInterval: ''
        };
    }
    componentDidUpdate() {
        requestAnimationFrame(() => {
            const _this = this;
            _this.targetTagDom = document.getElementById(TARGET_TAG_ID_NAME);
            _this.targetTagDom?.addEventListener('click', _this.targetTagClickHandler);
        });
    }
    componentWillUnmount() {
        this.targetTagDom?.removeEventListener('click', this.targetTagClickHandler);
    }
    targetTagClickHandler = () => {
        this.props.targetSettingStore.changeTargetType(enum_target_type.positiveRate);
        history.push('/targetSetting');
    };

    render() {
        const _this = this;
        const { activeData, activeInterval } = this.state;
        const { data, dateType, xAxisType, areaType, participateData, clickHandler } = this.props;
        const { targetData } = this.props.targetSettingStore;
        let xKeyName = '';
        if (xAxisType === enum_xAxis_type.time) {
            switch (dateType) {
                case enum_date_type.day:
                    xKeyName = 'f_indate';
                    break;
                case enum_date_type.week:
                    xKeyName = 'week';
                    break;
                case enum_date_type.month:
                    xKeyName = 'month';
                    break;
            }
        } else {
            xKeyName = areaType;
        }
        // 计算x轴的value个数
        const getXValueCount = () => {
            const xAxisObject = {};
            data.forEach(item => !xAxisObject[item[xKeyName]] && (xAxisObject[item[xKeyName]] = item));
            return Object.keys(xAxisObject).length;
        };
        // 计算辅助线文本的偏移量
        const getGuideOffset = length => {
            // 以20个tick需要便宜0.5个tick为基准，换算偏移量
            return length + (length / 20 - 1) * 0.5;
        };
        // 好评率geom
        const geomList: IGeom[] = [
            {
                type: enum_geom_type.LINE,
                size: getSize(3),
                configList: [
                    {
                        typeKey: 'positiveRate',
                        typeName: (data: IPositiveRateDODItem) => data.f_score_type?.toString() || '',
                        color: type => {
                            switch (+type) {
                                case enum_comment_type.wash:
                                    return '#FDD903';
                                case enum_comment_type.machine:
                                    return '#ED344C';
                                case enum_comment_type.environment:
                                    return '#4A90E2';
                                default:
                                    return 'transparent';
                            }
                        }
                    }
                ]
            }
        ];

        // 坐标轴配置
        const xConfig = {
            name: xKeyName,
            line: {
                // x轴宽度 颜色
                lineWidth: 1,
                stroke: '#979797'
            },
            tickLine: null,
            label: {
                offset: 0, // 数值，设置坐标轴文本 label 距离坐标轴线的距离
                autoRotate: false, // 文本是否需要自动旋转，默认为 true
                htmlTemplate: (text, item, index) => {
                    const axisContent = {
                        line1: '',
                        line2: ''
                    };
                    if (xAxisType === enum_xAxis_type.time) {
                        switch (dateType) {
                            case enum_date_type.day:
                                axisContent.line1 =
                                    text === activeInterval ? formatDate(text, 'MM/DD') : getWeekDayName(text);
                                // axisContent.line2 = '晴';
                                break;
                            case enum_date_type.week:
                                const weekArr = text.split('-');
                                axisContent.line1 = `${+weekArr[1]}周`;
                                axisContent.line2 = `${+weekArr[0]}`;
                                break;
                            case enum_date_type.month:
                                const monthArr = text.split('-');
                                axisContent.line1 = text === activeInterval ? `${+monthArr[1]}月` : monthArr[1];
                                axisContent.line2 = monthArr[0];
                                break;
                        }
                    } else {
                        axisContent.line1 = simpleRegionName(text);
                    }
                    return `<div class="${styles.dayAxis} ${text === activeInterval ? styles.activeDayAxis : ''}">
                        <div class=${styles.xAxisLine1} 
                            style=${axisContent.line1 === '一' && text !== activeInterval ? 'color: #FF6704' : ''}
                        >
                            ${axisContent.line1}
                        </div>
                        <div class=${styles.xAxisLine2}>${axisContent.line2}</div>
                    </div>`;
                }
            }
        };
        const yConfig = {
            name: 'positiveRate',
            visible: false
        };

        const toolTipConfig = {
            shared: true,
            useHtml: true,
            showCrosshairs: true,
            crosshairs: {
                type: 'y',
                style: {
                    // 图形样式
                    stroke: '#4A4A4A' // 边框的颜色
                }
            },
            htmlContent: (title, items) => {
                let washRate = initPositiveRateDODItem.positiveRate,
                    environmentRate = initPositiveRateDODItem.positiveRate,
                    machineRate = initPositiveRateDODItem.positiveRate,
                    participateRate = initParticipateRateDODItem.rate;
                items.forEach(item => {
                    const { _origin: data } = item.point;
                    switch (item.name) {
                        case enum_comment_type.wash.toString():
                            washRate = data.positiveRate;
                            break;
                        case enum_comment_type.environment.toString():
                            environmentRate = data.positiveRate;
                            break;
                        case enum_comment_type.machine.toString():
                            machineRate = data.positiveRate;
                            break;
                        case '参评率':
                            participateRate = data.rate;
                            break;
                    }
                });
                const totalRate = ((washRate + environmentRate + machineRate) / 3).toFixed(2);
                return `<div class=${styles.diyToolContainer}>
                    <div class=${styles.diyToolHeader}>
                        <div>好评率：</div>
                        <div class=${styles.orderValue}>${totalRate}%</div>
                    </div>
                    <div class=${styles.diyToolLegend}>
                        <div class=${styles.diyToolLegendRow}>
                            <div class=${styles.diyToolLegendRowHeader}>
                                <div class=${styles.icon} style="background: #ED344C"></div>
                                <div>设备</div>
                            </div>
                            <div class=${styles.diyToolLegendRowValue}>${machineRate}%</div>
                        </div>
                        <div class=${styles.diyToolLegendRow}>
                            <div class=${styles.diyToolLegendRowHeader}>
                                <div class=${styles.icon} style="background: #4A90E2"></div>
                                <div>环境</div>
                            </div>
                            <div class=${styles.diyToolLegendRowValue}>${environmentRate}%</div>
                        </div>
                        <div class=${styles.diyToolLegendRow}>
                            <div class=${styles.diyToolLegendRowHeader}>
                                <div class=${styles.icon} style="background: #FDD903"></div>
                                <div>清洁</div>
                            </div>
                            <div class=${styles.diyToolLegendRowValue}>${washRate}%</div>
                        </div>
                    </div>
                    <div class=${styles.diyToolContent}>
                        ${xAxisType === enum_xAxis_type.time ? `<div>好评率目标：${targetData}%</div>` : ''}
                        <div class=${styles.diyToolContentRow}>
                            <div class=${styles.icon} style="background: #999999"></div>
                            <div>参评率：${participateRate}%</div>
                        </div>
                    </div>
                </div>`;
            }
        };

        const chartChildren = () => {
            const yKey = 'rate';
            const { maxY, minY } = getRange(participateData, 'rate');
            const { maxY: mainChartMaxY, minY: mainChartMinY } = getRange(data, yConfig.name);
            // 由于目标值可能未设定，或者设定了一个超出显示范围的值
            // targetDataLine 是绘制在图表上的目标值高度，不一定是真实高度，只是取区间内能绘制的最高或最低位置
            // realTarget 是显示的目标值文案
            let targetDataLine = targetData;
            if (targetData < mainChartMinY || targetData === '--') {
                targetDataLine = mainChartMinY;
            } else if (targetData > mainChartMaxY) {
                targetDataLine = mainChartMaxY;
            }
            return (
                <React.Fragment>
                    <View
                        data={participateData}
                        scale={{
                            [yKey]: {
                                min: minY,
                                max: maxY,
                                alias: '参评率'
                            }
                        }}
                    >
                        <Geom
                            type={enum_geom_type.LINE}
                            position={`${xConfig.name}*${yKey}`}
                            size={getSize(3)}
                            color="#999999"
                            opacity={1}
                        />
                    </View>
                    {xAxisType === enum_xAxis_type.time && (
                        <Guide>
                            <Guide.Line
                                // top // {boolean} 指定 guide 是否绘制在 canvas 最上层，默认为 false, 即绘制在最下层
                                start={[0, targetDataLine]} // 0 代表ticks索引，必须scale的type为非线性
                                end={[getGuideOffset(getXValueCount()), targetDataLine]} // 同 start
                                lineStyle={{
                                    stroke: '#615616', // 线的颜色
                                    lineDash: [1, 0], // 虚线的设置，实线
                                    opacity: 1,
                                    lineWidth: 3 // 线的宽度
                                }} // {object} 图形样式配置 https://bizcharts.net/products/bizCharts/api/graphic#线条样式
                            />
                            <Guide.Html
                                position={[getGuideOffset(getXValueCount()), targetDataLine]} // html 的中心位置， 值为原始数据值，支持 callback
                                offsetX={0}
                                offsetY={0}
                                html={`<div id=${TARGET_TAG_ID_NAME} class=${styles.guideContainer}>
                                <div class=${styles.guideTitle}>目标</div>
                                <div class=${styles.guideTag}>${targetData}%</div>
                            </div>`}
                            />
                        </Guide>
                    )}
                </React.Fragment>
            );
        };

        return (
            <div id="page-analysis-mainChart" className={styles.mainContainer}>
                <div className={styles.chartCard}>
                    <CompoundChart
                        data={data}
                        xConfig={xConfig}
                        yConfig={yConfig}
                        padding={['auto', '5%', 'auto', '2%']}
                        ifCanClick={xAxisType !== enum_xAxis_type.time && Boolean(activeInterval)}
                        scale={{
                            [xKeyName]: {
                                type: 'cat',
                                ticks: getTicks({
                                    length: getXValueCount(),
                                    activeTick: data.findIndex(item => item[xKeyName] === activeInterval)
                                })
                            }
                        }}
                        toolTipConfig={toolTipConfig}
                        geomList={geomList}
                        chartChildren={chartChildren()}
                        eventObj={{
                            onTooltipChange: debounce(event => {
                                const { _origin: data } = event.items[0].point;
                                _this.state.activeInterval !== data[xKeyName] &&
                                    _this.setState({
                                        activeData: data,
                                        activeInterval: data[xKeyName]
                                    });
                            }, 0),
                            onTooltipHide: debounce(event => {
                                activeInterval !== '' &&
                                    _this.setState({
                                        activeData: {},
                                        activeInterval: ''
                                    });
                            }, 0),
                            onPlotClick: debounce(event => {
                                if (activeInterval) {
                                    clickHandler(activeData);
                                }
                            }, 100)
                        }}
                    />
                </div>
            </div>
        );
    }
}

export default errBoundary(PositiveRateChart);
