import React from 'react';
import { findDOMNode } from 'react-dom';
import { observer, inject } from 'mobx-react';
import moment from 'moment';
import { errBoundary } from '@/components/ErrorBoundary';
import RegionSelector from '@/components/RegionSelector';
import { Modal, Table, DatePicker, ConfigProvider, Select } from 'antd';
import { UIStore } from '@/store/UI';
import FactoryStore, { enum_factory_type, enum_channel_type } from '@/store/Factory/typing';
import { CHANNEL_OPTIONS, FACTORY_TYPE_OPTIONS } from './constans';
import { debounce, isPC, formatDate } from '@/utils/method';
import {} from '@/utils/constant';
import zhCN from 'antd/es/locale/zh_CN';
import styles from './index.less';

const { RangePicker } = DatePicker;
const { Option } = Select;

const REF_NAME = 'tableContainer';
const CRITICAL_NUM = 3; // 临界数据条数
const SCROLL_SIZE = 30; // 每次滚动到底部，再加载几条数据

interface ICommonProps {
    ifShow: boolean; // 弹窗显示隐藏状态
    toggleModal: Function; // 弹窗显示隐藏的处理
    okHandler: (values: string[] | number[], data?: any[]) => void; // 确认处理
    factoryStore: FactoryStore;
}

interface IFactoryModalProps extends ICommonProps {
    ifResize: boolean; // 必须传uiStore.ifResize 窗口变化的响应布局
    changeResize: Function; // 必须传uiStore.changeResize
}

interface IState {
    modalWidth: number; // 弹窗宽度
    initSelectedFactoryIds: any[]; // 记录初始选中站点，取消时恢复
    selectedFactoryIds: number[]; // 选中的站点id列表
    selectedFactoryData: any[]; // 选中的站点数据列表
    selectedRegionList: string[]; // 选中的区域
    selectedStartDate: string; // 当前选中的开始日期
    selectedEndDate: string; // 当前选中的结束日期
    selectedChannel: enum_channel_type | null; // 选中的渠道
    selectedFactoryType: enum_factory_type | null; // 选中的门店类型
    tableList: any[]; // 表格中显示的列表
}

@inject('factoryStore')
@observer
class FactoryModal extends React.Component<IFactoryModalProps, IState> {
    private tableContainer;
    private tableBody;
    private tableRowHeight;

    constructor(props: IFactoryModalProps) {
        super(props);
        this.state = {
            modalWidth: window.document.body.offsetWidth * (isPC() ? 0.6 : 0.8),
            initSelectedFactoryIds: [],
            selectedFactoryIds: [],
            selectedFactoryData: [],
            selectedRegionList: [],
            selectedStartDate: '',
            selectedEndDate: '',
            selectedChannel: null,
            selectedFactoryType: null,
            tableList: []
        };
    }
    componentDidMount() {
        const _this = this;
        this.initData();
        window.onresize = () => {
            _this.props.changeResize();
        };
    }
    componentWillUnmount() {
        this.tableBody?.removeEventListener('scroll', this.scrollHandler);
    }
    componentDidUpdate(preProps: IFactoryModalProps, preState: IState) {
        const _this = this;
        const { tableList, selectedFactoryIds } = this.state;
        const { ifShow } = this.props;
        if (preState.tableList.length !== tableList.length || preProps.ifShow !== ifShow) {
            ifShow &&
                _this.setState({
                    initSelectedFactoryIds: selectedFactoryIds // 显示弹窗 备份已选的站点id
                });
            window.requestAnimationFrame(() => {
                _this.tableContainer = findDOMNode(this.refs[REF_NAME]);
                _this.tableBody = _this.tableContainer && _this.tableContainer.querySelector('.ant-table-body');
                _this.tableRowHeight = _this.tableBody && _this.tableBody.querySelector('.ant-table-row')?.clientHeight;
                _this.tableBody?.addEventListener('scroll', _this.scrollHandler);
            });
        }
        if (preProps.ifResize !== this.props.ifResize) {
            _this.setState({
                modalWidth: window.document.body.offsetWidth * (isPC() ? 0.6 : 0.8)
            });
        }
    }
    scrollHandler = debounce(() => {
        const _this = this;
        const criticalVal = _this.tableRowHeight * CRITICAL_NUM;
        if (_this.tableBody.scrollHeight - _this.tableBody.scrollTop - _this.tableBody.offsetHeight <= criticalVal) {
            const { tableList } = _this.state;
            const { baseList } = _this.props.factoryStore;
            const newTableList = tableList.concat(baseList.slice(tableList.length, tableList.length + SCROLL_SIZE));
            _this.tableBody?.removeEventListener('scroll', _this.scrollHandler);
            _this.setState({
                tableList: newTableList
            });
        }
    }, 100);

    /**
     * 数据加载
     * @return {void}
     */
    initData = async () => {
        const _this = this;
        const {
            selectedRegionList,
            selectedStartDate,
            selectedEndDate,
            selectedChannel,
            selectedFactoryType
        } = _this.state;
        const [f_province_id, f_city_id, f_district_id] = selectedRegionList;
        const { factoryStore } = _this.props;
        const params = {
            f_province_id,
            f_city_id,
            f_district_id,
            businessCategory: selectedChannel,
            operationType: selectedFactoryType
        };
        if (selectedStartDate && selectedEndDate)
            params['f_work_start_time'] = `${selectedStartDate},${selectedEndDate}`;
        const result = await factoryStore.initLoad(params);
        const { ifSuccess, data } = result;
        ifSuccess &&
            this.setState({
                tableList: data.slice(0, SCROLL_SIZE)
            });
    };
    handleOk = e => {
        const { selectedFactoryIds, selectedFactoryData } = this.state;
        const { toggleModal, okHandler } = this.props;
        okHandler(selectedFactoryIds, selectedFactoryData);
        toggleModal();
    };
    handleCancel = e => {
        this.setState({
            selectedFactoryIds: this.state.initSelectedFactoryIds // 取消，隐藏弹窗 恢复已选的站点id
        });
        this.props.toggleModal();
    };
    clickSelected = newSelectedItem => {
        const { selectedFactoryIds, selectedFactoryData } = this.state;
        const copyIds = [...selectedFactoryIds];
        const copyData = [...selectedFactoryData];
        const index = copyIds.findIndex(item => item === newSelectedItem.f_id);
        if (index === -1) {
            this.setState({
                selectedFactoryIds: [...copyIds, newSelectedItem.f_id],
                selectedFactoryData: [...copyData, newSelectedItem]
            });
        } else {
            copyIds.splice(index, 1);
            copyData.splice(index, 1);
            this.setState({
                selectedFactoryIds: copyIds,
                selectedFactoryData: copyData
            });
        }
    };
    onSelectChange = (selectedRowKeys, selectedRows) => {
        this.setState({
            selectedFactoryIds: selectedRowKeys,
            selectedFactoryData: selectedRows
        });
    };
    selectAllHandler = ifSelected => {
        const { baseList } = this.props.factoryStore;
        // 因为列表是动态显示的，所以全选和取消全选需要特殊处理，除了已经显示的站点，还要加上还未加载的站点
        if (ifSelected) {
            this.setState({
                selectedFactoryIds: baseList.map(item => item.f_id),
                selectedFactoryData: baseList
            });
        } else {
            this.setState({
                selectedFactoryIds: [],
                selectedFactoryData: []
            });
        }
    };
    onRegionChange = (values: string[]) => {
        const _this = this;
        _this.setState(
            {
                selectedFactoryIds: [],
                selectedFactoryData: [],
                selectedRegionList: values
            },
            _this.initData
        );
    };
    /**
     * 日期选择器变化
     * @param {Moment[]} value 选中的日期 moment value[0]是开始时间  value[1]是结束时间
     * @return {void}
     */
    changeDate = value => {
        if (value) {
            const [startDate, endDate] = value;
            const getDateStr = date => moment(date).format('YYYY-MM-DD');
            this.setState(
                { selectedStartDate: getDateStr(startDate), selectedEndDate: getDateStr(endDate) },
                this.initData
            );
        } else {
            this.setState({ selectedStartDate: '', selectedEndDate: '' }, this.initData);
        }
    };
    changeChannel = value => {
        this.setState({ selectedChannel: value }, this.initData);
    };
    changeFactoryType = value => {
        this.setState({ selectedFactoryType: value }, this.initData);
    };

    render() {
        const _this = this;
        const { modalWidth, selectedFactoryIds, tableList } = _this.state;
        const { ifShow, factoryStore } = _this.props;
        const { ifBaseListLoading } = factoryStore;
        const columns = [
            {
                title: '站点名称',
                dataIndex: 'f_name',
                align: 'center'
            },
            {
                title: '开业时间',
                dataIndex: 'f_work_start_time',
                align: 'center',
                // width: 150,
                render: text => formatDate(text, 'YYYY-MM-DD')
            }
        ];
        const rowSelection = {
            columnWidth: 50,
            selectedRowKeys: selectedFactoryIds,
            onChange: _this.onSelectChange,
            onSelectAll: _this.selectAllHandler
        };
        return (
            <Modal
                width={modalWidth}
                title="选择门店"
                visible={ifShow}
                onOk={_this.handleOk}
                onCancel={_this.handleCancel}
                cancelText="取消"
                okText="确定"
            >
                <div className={styles.wrapper}>
                    <div className={styles.header}>
                        <div id="regionContainer" className={styles.selectorItem}>
                            <RegionSelector selectedHandler={_this.onRegionChange} />
                        </div>
                        <div className={styles.selectorItem}>
                            <ConfigProvider locale={zhCN}>
                                <RangePicker
                                    placeholder={['开业时间', '开业时间']}
                                    onChange={_this.changeDate}
                                    format="YYYY/MM/DD"
                                />
                            </ConfigProvider>
                        </div>
                        <div className={styles.selectorItem}>
                            <Select
                                allowClear
                                placeholder="全部渠道"
                                style={{ width: 120 }}
                                onChange={this.changeChannel}
                            >
                                {CHANNEL_OPTIONS.map(item => {
                                    return (
                                        <Option key={item} value={item}>
                                            {item}
                                        </Option>
                                    );
                                })}
                            </Select>
                        </div>
                        <div className={styles.selectorItem}>
                            <Select
                                allowClear
                                placeholder="全部类型"
                                style={{ width: 120 }}
                                onChange={this.changeFactoryType}
                            >
                                {FACTORY_TYPE_OPTIONS.map(item => {
                                    return (
                                        <Option key={item.value} value={item.value}>
                                            {item.name}
                                        </Option>
                                    );
                                })}
                            </Select>
                        </div>
                    </div>
                    <div ref={REF_NAME} className={styles.container}>
                        <Table
                            onRow={record => ({
                                onClick: () => _this.clickSelected(record)
                            })}
                            rowKey="f_id"
                            loading={ifBaseListLoading}
                            columns={columns}
                            dataSource={tableList}
                            rowSelection={rowSelection}
                            pagination={false}
                            scroll={{ y: window.document.body.offsetHeight * 0.3 }}
                            locale={{
                                emptyText: '暂无站点'
                            }}
                        />
                    </div>
                </div>
            </Modal>
        );
    }
}

interface IProps extends ICommonProps {
    uiStore?: UIStore; // 就是store.uiStore
}

const Index = inject('uiStore')(
    observer((props: IProps) => {
        const { uiStore } = props;
        return (
            <FactoryModal
                {...props}
                ifResize={uiStore?.ifResize || false}
                changeResize={uiStore?.changeResize || (() => {})}
            />
        );
    })
);

export default errBoundary(Index);
